"""
Generate 888+ atomic knowledge points.
Each point: title, explanation, code example, mini-game, quiz.
12 weeks, smooth learning curve.
"""

import json
from pathlib import Path

ALL_KP = []

def kp(week, module, title, explanation, code, game, quiz_q, quiz_opts, quiz_correct, quiz_explain):
    ALL_KP.append({
        "week": week, "module": module, "title": title,
        "explanation": explanation, "code": code, "game": game,
        "quiz": {"question": quiz_q, "options": quiz_opts, "correct": quiz_correct, "explanation": quiz_explain},
    })

# ============================================================
# HELPER: Generate many knowledge points from templates
# ============================================================

def gen_basics(week, module, items):
    """items: list of (title, expl, code, game, q, opts, ans, qexpl)"""
    for title, expl, code, game, q, opts, ans, qexpl in items:
        kp(week, module, title, expl, code, game, q, opts, ans, qexpl)

