    ("len() function", "len() returns the number of items in a sequence.", "print(len('hello'))     # 5\nprint(len([1, 2, 3]))   # 3\nprint(len({'a': 1}))    # 1\nprint(len((1, 2)))      # 2", "Game: What is len('Python')?", "What does len() return?", ["The last item", "The number of items", "The first item", "The type"], 1, "len() returns the count of items in a string, list, dict, etc."),
    ("input() function", "input() reads a line of text from the user. Always returns a string.", "name = input('Your name: ')\nprint(f'Hello {name}!')\n\n# input() always returns str!\nage = input('Age: ')\nage = int(age)  # Convert to int", "Game: What type does input() return?", "What does input() return?", ["An integer", "A string", "A boolean", "None"], 1, "input() always returns a string. Convert with int() or float() if needed."),
    ("print() function", "print() outputs text to the screen. Can take multiple arguments.", "print('Hello')\nprint('a', 'b', 'c')       # a b c\nprint('a', 'b', sep='-')   # a-b\nprint('no newline', end='')\nprint(' continues')", "Game: What does print(1, 2, 3, sep='-') output?", "What does print() do?", ["Reads input", "Outputs text to screen", "Creates a file", "Imports a module"], 1, "print() outputs to the screen. Use sep and end to customize."),
