# More Python function topics
py_func_detailed = [
    ("Defining functions", "Use def to create a function. Name, parameters, body, return.", "def greet(name):\n    return f'Hello, {name}!'\n\nprint(greet('Alice'))  # Hello, Alice!", "Game: Write a function that doubles a number.", "How do you define a function?", ["function name():", "def name():", "func name():", "fn name():"], 1, "def defines a function in Python."),
    ("Parameters vs arguments", "Parameters are in the definition. Arguments are the values you pass.", "def add(a, b):     # a, b = parameters\n    return a + b\n\nresult = add(3, 5)  # 3, 5 = arguments", "Game: What are parameters and arguments here?\ndef square(n): return n * n\nsquare(4)", "What are parameters?", ["Values passed in", "Names in the function definition", "Return values", "Global variables"], 1, "Parameters = definition names. Arguments = actual values."),
    ("Return values", "return sends a value back. Without it, function returns None.", "def double(n):\n    return n * 2\n\ndef say_hi():\n    print('hi')\n    # Returns None implicitly\n\nprint(double(5))  # 10\nprint(say_hi())   # hi, then None", "Game: What does this return?\ndef f(x): return x + 1\nf(5)", "What does return do?", ["Prints to screen", "Sends a value back to the caller", "Stops the program", "Creates a variable"], 1, "return sends a value back. Without it, returns None."),
    ("Default parameters", "Give parameters default values. Used when no argument is passed.", "def greet(name, greeting='Hello'):\n    return f'{greeting}, {name}!'\n\ngreet('Alice')           # Hello, Alice!\ngreet('Bob', 'Hi')       # Hi, Bob!", "Game: What does greet('Alice') print?\ndef greet(name, msg='Hey'):\n    return f'{msg} {name}'", "What is a default parameter?", ["Required parameter", "Parameter with fallback value", "Global variable", "Error"], 1, "Default parameters have fallback values."),
    ("Variable scope", "Variables inside a function are local. Outside are global.", "x = 10  # Global\n\ndef foo():\n    x = 20  # Local (different!)\n    print(x)  # 20\n\nfoo()\nprint(x)  # 10 (global unchanged)", "Game: What prints?\nx = 1\ndef f():\n    x = 99\nf()\nprint(x)", "What is scope?", ["Where a variable is visible", "The type of variable", "The name of variable", "The size"], 1, "Scope = where a variable is visible. Local = inside function."),
    ("*args", "*args collects extra positional arguments into a tuple.", "def total(*numbers):\n    return sum(numbers)\n\ntotal(1, 2, 3)      # 6\ntotal(1, 2, 3, 4)   # 10", "Game: What does total(10, 20) return?\ndef total(*args): return sum(args)", "What does *args do?", ["Creates a list", "Collects extra positional arguments", "Makes args optional", "Deletes args"], 1, "*args collects extra positional arguments into a tuple."),
    ("**kwargs", "**kwargs collects extra keyword arguments into a dictionary.", "def show(**kwargs):\n    for k, v in kwargs.items():\n        print(f'{k}: {v}')\n\nshow(name='Alice', age=25)\n# name: Alice\n# age: 25", "Game: What does kwargs contain?\ndef f(**kwargs): print(kwargs)\nf(x=1, y=2)", "What does **kwargs collect?", ["Positional args", "Keyword args as dict", "File paths", "Errors"], 1, "**kwargs collects keyword arguments into a dictionary."),
    ("Lambda functions", "Lambda = small anonymous function in one line.", "double = lambda x: x * 2\nprint(double(5))  # 10\n\nnums = [1, 2, 3]\nsquared = list(map(lambda x: x**2, nums))\nprint(squared)  # [1, 4, 9]", "Game: What does (lambda a, b: a + b)(3, 4) return?", "What is a lambda?", ["Named function", "Small anonymous function", "A class", "A module"], 1, "Lambda = small anonymous function. lambda args: expression."),
    ("Closures", "Closure = function that remembers variables from its enclosing scope.", "def make_adder(n):\n    def adder(x):\n        return x + n  # Remembers n!\n    return adder\n\nadd5 = make_adder(5)\nprint(add5(3))  # 8\nprint(add5(10)) # 15", "Game: What does this print?\ndef outer(x):\n    def inner(): return x\n    return inner\nf = outer(42)\nprint(f())", "What does a closure remember?", ["Everything", "Variables from enclosing function", "Nothing", "Only globals"], 1, "Closures remember variables from the function that created them."),
    ("Decorators basics", "Decorator = function that wraps another function to add behavior.", "def log(func):\n    def wrapper(*args):\n        print(f'Calling {func.__name__}')\n        return func(*args)\n    return wrapper\n\n@log\ndef add(a, b):\n    return a + b\n\nadd(3, 5)  # Prints: Calling add, returns 8", "Game: What does @log do?\nA) Deletes the function\nB) Adds logging before it runs\nC) Changes the name", "What does a decorator do?", ["Deletes a function", "Adds behavior without changing the function", "Creates a module", "Imports code"], 1, "Decorators wrap functions to add behavior."),
    ("Decorators with arguments", "Decorators can take arguments by adding another layer of wrapping.", "def repeat(n):\n    def decorator(func):\n        def wrapper(*args):\n            for _ in range(n):\n                func(*args)\n        return wrapper\n    return decorator\n\n@repeat(3)\ndef say_hi():\n    print('Hi!')\n\nsay_hi()  # Hi! Hi! Hi!", "Game: What does @repeat(2) do?\nA) Runs the function twice\nB) Deletes the function\nC) Imports it twice", "How do decorators take arguments?", ["Directly", "With an outer function that returns the decorator", "They cannot", "With *args"], 1, "Decorator with args: def repeat(n) -> def decorator(func) -> def wrapper."),
]

