# Python classes detailed
py_class_detailed = [
    ("Classes: blueprints", "A class defines the structure and behavior of objects. Like a blueprint for houses.", "class Dog:\n    def __init__(self, name):\n        self.name = name\n    def bark(self):\n        return f'{self.name}: Woof!'\n\nrex = Dog('Rex')\nprint(rex.bark())  # Rex: Woof!", "Game: Create a Cat class with meow().", "What is a class?", ["A function", "A blueprint for objects", "A variable", "A loop"], 1, "Classes define structure and behavior. Objects are instances."),
    ("__init__ constructor", "__init__ runs when creating an object. Sets up initial state.", "class Person:\n    def __init__(self, name, age):\n        self.name = name\n        self.age = age\n\nalice = Person('Alice', 25)\nprint(alice.name)  # Alice", "Game: When does __init__ run?\nA) At import\nB) When creating an object\nC) When calling a method", "When does __init__ run?", ["At import", "When creating an object", "When calling methods", "Never"], 1, "__init__ runs when you create: obj = ClassName()."),
    ("self parameter", "self refers to the current instance. Every method needs it.", "class Counter:\n    def __init__(self):\n        self.count = 0\n    def increment(self):\n        self.count += 1\n        return self\n\nc = Counter()\nc.increment().increment()\nprint(c.count)  # 2", "Game: Why does every method need self?\nA) Optional\nB) To access instance data\nC) To access the class", "What is self?", ["The class", "The current instance", "A global variable", "The parent class"], 1, "self = current instance. Methods use it to access the object's data."),
    ("Instance variables", "Variables that belong to each instance. Each object has its own copy.", "class Student:\n    def __init__(self, name):\n        self.name = name  # Instance variable\n        self.grades = []\n\na = Student('Alice')\nb = Student('Bob')\na.grades.append(95)\nprint(a.grades)  # [95]\nprint(b.grades)  # [] (separate!)", "Game: If Alice adds a grade, does Bob see it?", "What is an instance variable?", ["Shared by all instances", "Unique to each instance", "A global variable", "A function"], 1, "Instance variables are unique to each object."),
    ("Class variables", "Variables shared by all instances. Defined at class level.", "class Student:\n    school = 'Python Academy'  # Class variable\n    def __init__(self, name):\n        self.name = name\n\na = Student('Alice')\nb = Student('Bob')\nprint(a.school)  # Python Academy\nprint(b.school)  # Same!", "Game: Is school the same for all students?", "What is a class variable?", ["Unique to each instance", "Shared by all instances", "A function", "An error"], 1, "Class variables are shared. All instances see the same value."),
    ("Instance methods", "Functions defined in a class. Always take self as first parameter.", "class Calculator:\n    def __init__(self):\n        self.result = 0\n    def add(self, n):\n        self.result += n\n        return self\n    def show(self):\n        return self.result\n\nc = Calculator()\nc.add(5).add(3)\nprint(c.show())  # 8", "Game: What does method chaining require?\nA) Returning self\nB) Returning None\nC) Returning the class", "What is an instance method?", ["A function outside a class", "A function inside a class that takes self", "A class variable", "A module"], 1, "Methods are functions in a class. They take self to access instance data."),
    ("Inheritance", "Child class gets methods from parent. Can override or extend.", "class Animal:\n    def speak(self):\n        return '...'\n\nclass Dog(Animal):\n    def speak(self):\n        return 'Woof!'\n\nclass Cat(Animal):\n    def speak(self):\n        return 'Meow!'\n\nprint(Dog().speak())  # Woof!", "Game: What does Cat().speak() return?\nclass Animal: def speak(self): return '...'\nclass Cat(Animal): def speak(self): return 'Meow!'", "What does inheritance do?", ["Copies code", "Reuses methods from parent class", "Deletes parent", "Creates a function"], 1, "Inheritance lets child classes reuse parent functionality."),
    ("Method overriding", "Child class can replace parent methods with its own implementation.", "class Shape:\n    def area(self):\n        return 0\n\nclass Circle(Shape):\n    def __init__(self, radius):\n        self.radius = radius\n    def area(self):  # Override!\n        return 3.14 * self.radius ** 2\n\nprint(Circle(5).area())  # 78.5", "Game: What happens when child overrides parent method?\nA) Both run\nB) Child's version runs\nC) Parent's version runs", "What is method overriding?", ["Calling parent method", "Replacing parent method with child's version", "Deleting the method", "Importing the method"], 1, "Overriding: child defines same method name, its version runs instead."),
    ("super() function", "super() calls the parent class method from the child.", "class Animal:\n    def __init__(self, name):\n        self.name = name\n\nclass Dog(Animal):\n    def __init__(self, name, breed):\n        super().__init__(name)  # Call parent!\n        self.breed = breed\n\nrex = Dog('Rex', 'Lab')\nprint(rex.name)   # Rex\nprint(rex.breed)  # Lab", "Game: What does super().__init__() do?\nA) Creates a new object\nB) Calls the parent's __init__\nC) Deletes the object", "What does super() do?", ["Creates a new class", "Calls the parent class method", "Deletes the parent", "Imports the parent"], 1, "super() calls the parent class method. Used to extend, not replace."),
    ("Dataclasses", "@dataclass auto-generates __init__, __repr__, __eq__ from type hints.", "from dataclasses import dataclass\n\n@dataclass\nclass Point:\n    x: float\n    y: float\n\np = Point(3.0, 4.0)\nprint(p)  # Point(x=3.0, y=4.0)\nprint(p == Point(3.0, 4.0))  # True", "Game: What does @dataclass generate?\nA) Only __init__\nB) __init__, __repr__, __eq__\nC) Nothing", "What does @dataclass do?", ["Makes class abstract", "Auto-generates boilerplate methods", "Makes immutable", "Deletes the class"], 1, "@dataclass reads type hints and generates __init__, __repr__, __eq__."),
    ("Property decorator", "@property lets you define methods that act like attributes.", "class Circle:\n    def __init__(self, radius):\n        self.radius = radius\n    @property\n    def area(self):\n        return 3.14 * self.radius ** 2\n\nc = Circle(5)\nprint(c.area)  # 78.5 (no parentheses!)", "Game: What is the difference between @property and a regular method?\nA) @property uses no parentheses\nB) They are the same\nC) @property is faster", "What does @property do?", ["Creates a variable", "Makes a method act like an attribute", "Deletes the method", "Imports code"], 1, "@property lets you call methods without parentheses: c.area instead of c.area()."),
]

