# Python async detailed
py_async_detailed = [
    ("What is async?", "Async lets your program do other work while waiting for slow operations.", "import asyncio\n\nasync def fetch():\n    print('Fetching...')\n    await asyncio.sleep(1)\n    print('Done!')\n    return 42\n\nasyncio.run(fetch())", "Game: Why use async?\nA) Use multiple CPUs\nB) Do other work while waiting\nC) Write less code", "What does async do?", ["Uses multiple CPUs", "Does other work while waiting", "Runs faster", "Deletes code"], 1, "Async lets the program handle other tasks while waiting."),
    ("async def", "async def creates a coroutine. It doesn't run immediately.", "import asyncio\n\nasync def hello():\n    return 'Hello!'\n\n# Calling hello() doesn't run it!\ncoro = hello()\nprint(coro)  # <coroutine object>\nresult = asyncio.run(coro)  # Now it runs", "Game: Does calling an async function run it immediately?\nA) Yes\nB) No, it creates a coroutine", "What does async def create?", ["A regular function", "A coroutine", "A class", "A variable"], 1, "async def creates a coroutine. You must await it or use asyncio.run()."),
    ("await keyword", "await pauses the coroutine until the result is ready.", "import asyncio\n\nasync def get_data():\n    await asyncio.sleep(1)  # Pause 1 second\n    return 'data'\n\nasync def main():\n    data = await get_data()  # Wait for result\n    print(data)\n\nasyncio.run(main())", "Game: What does await do?\nA) Blocks everything\nB) Pauses this coroutine, others can run\nC) Creates a thread", "What does await do?", ["Blocks everything", "Pauses this coroutine, lets others run", "Creates a thread", "Stops the program"], 1, "await pauses this coroutine but not the event loop."),
    ("asyncio.gather", "Run multiple coroutines concurrently. Wait for all to finish.", "import asyncio\n\nasync def task(name, delay):\n    await asyncio.sleep(delay)\n    return f'{name} done'\n\nasync def main():\n    results = await asyncio.gather(\n        task('A', 2),\n        task('B', 1),\n    )\n    print(results)  # ['A done', 'B done']\n\nasyncio.run(main())", "Game: If A=2s, B=1s, how long does gather take?\nA) 3s\nB) 2s\nC) 1s", "What does gather() do?", ["Runs sequentially", "Runs concurrently, waits for all", "Takes the fastest", "Cancels tasks"], 1, "gather() runs concurrently. Total time = longest task."),
    ("async for", "Iterate over async iterables that yield values over time.", "import asyncio\n\nasync def numbers():\n    for i in range(3):\n        await asyncio.sleep(0.5)\n        yield i\n\nasync def main():\n    async for n in numbers():\n        print(n)  # 0, 1, 2\n\nasyncio.run(main())", "Game: What does async for do?\nA) Same as regular for\nB) Iterates over async iterables\nC) Creates a list", "What is async for?", ["Same as regular for", "Iterates over async iterables", "Creates a loop", "Deletes items"], 1, "async for iterates over async generators/iterables."),
    ("async with", "Async context managers for resources that need setup/cleanup.", "import asyncio\n\nclass AsyncFile:\n    async def __aenter__(self):\n        print('Opening...')\n        return self\n    async def __aexit__(self, *args):\n        print('Closing...')\n\nasync def main():\n    async with AsyncFile():\n        print('Working...')\n\nasyncio.run(main())", "Game: When does __aexit__ run?\nA) On entry\nB) On exit from the block\nC) Never", "What does async with do?", ["Creates a thread", "Manages async resource lifecycle", "Blocks the program", "Imports a module"], 1, "async with manages async resource setup and cleanup."),
]

gen_basics(4, "py-async", py_async_detailed)

# Python type system detailed
py_type_detailed = [
    ("Why type hints?", "Type hints document expected types. Catch bugs before runtime.", "def greet(name: str) -> str:\n    return f'Hello, {name}!'\n\ngreet(42)  # Warning: expected str, got int", "Game: What does -> str mean?\nA) Returns a string\nB) Takes a string\nC) Deletes a string", "What do type hints do?", ["Make code slower", "Document types and catch errors", "Delete variables", "Import modules"], 1, "Type hints document types and catch errors before running."),
    ("Basic type hints", "Use int, str, float, bool. For collections: list[int], dict[str, int].", "def process(names: list[str]) -> dict[str, int]:\n    return {name: len(name) for name in names}", "Game: How to hint a list of ints?\nA) list\nB) list[int]\nC) [int]\nD) int[]", "How to hint a list of integers?", ["list", "list[int]", "[int]", "int[]"], 1, "Use list[int] for a list of integers."),
    ("Optional types", "Optional[X] = X or None. Same as X | None.", "from typing import Optional\n\ndef find(id: int) -> Optional[str]:\n    if id == 1:\n        return 'Alice'\n    return None", "Game: What does Optional[str] mean?\nA) Always string\nB) String or None\nC) Optional parameter", "What does Optional[str] mean?", ["Always string", "String or None", "Optional parameter", "Empty string"], 1, "Optional[str] = str or None."),
    ("TypeVar generics", "TypeVar creates placeholder types for generic functions.", "from typing import TypeVar\nT = TypeVar('T')\n\ndef first(items: list[T]) -> T:\n    return items[0]\n\nfirst([1, 2])    # T = int\nfirst(['a', 'b'])  # T = str", "Game: What type does first([1,2,3]) return?\nA) Any\nB) int\nC) str", "What does TypeVar enable?", ["Deleting types", "Type-safe generic functions", "Importing modules", "Creating classes"], 1, "TypeVar creates placeholder types for generics."),
    ("Callable types", "Type hint for functions.", "from typing import Callable\n\ndef apply(fn: Callable[[int], int], x: int) -> int:\n    return fn(x)\n\napply(lambda x: x * 2, 5)  # 10", "Game: What does Callable[[int], int] mean?\nA) Takes int, returns int\nB) Takes any args\nC) Returns None", "What does Callable type hint?", ["A class", "A function type with specific signature", "A variable", "An error"], 1, "Callable[[arg_types], return_type] types functions."),
    ("Literal types", "Restrict values to specific exact values.", "from typing import Literal\n\ndef move(direction: Literal['up', 'down', 'left', 'right']):\n    print(f'Moving {direction}')\n\nmove('up')    # OK\nmove('fly')   # Error!", "Game: What values can Literal['a', 'b', 'c'] hold?", "What does Literal type do?", ["Any value", "Restricts to specific exact values", "Deletes values", "Imports values"], 1, "Literal restricts to specific string/number values."),
    ("Union types", "A value can be one of several types. Use | or Union[].", "from typing import Union\n\ndef process(value: Union[str, int]) -> str:\n    if isinstance(value, str):\n        return value.upper()\n    return str(value)\n\n# Or using | (Python 3.10+)\ndef process(value: str | int) -> str:\n    pass", "Game: What does str | int mean?\nA) String and int\nB) String or int\nC) Neither", "What is a union type?", ["One type only", "One of several types", "All types", "No types"], 1, "Union = value can be one of several types."),
    ("TypeAlias", "Create readable names for complex types.", "from typing import TypeAlias\n\nUserId: TypeAlias = int\nUserMap: TypeAlias = dict[str, list[str]]\n\ndef get_user(id: UserId) -> UserMap:\n    return {'name': ['Alice']}", "Game: What does TypeAlias do?\nA) Creates a new type\nB) Creates a readable name for a type\nC) Deletes a type", "What is TypeAlias?", ["A new type", "A readable name for complex types", "A function", "An error"], 1, "TypeAlias creates readable names for complex types."),
]

