# Python modules detailed
py_mod_detailed = [
    ("Importing modules", "Use import to bring in code from other files or libraries.", "import math\nprint(math.pi)        # 3.14159...\nprint(math.sqrt(16))  # 4.0\n\nfrom math import pi, sqrt\nprint(pi)  # 3.14159...", "Game: What is the difference?\nA) import math\nB) from math import sqrt", "How do you import a module?", ["import module", "require module", "include module", "use module"], 1, "import loads a module and makes its functions available."),
    ("Creating modules", "Any .py file is a module. Put functions in a file, import from another.", "# utils.py\ndef double(n): return n * 2\n\n# main.py\nfrom utils import double\nprint(double(5))  # 10", "Game: You have helpers.py with add(). How to use it?", "How do you create a module?", ["Create a .py file", "Use the module keyword", "Import from Python", "Cannot create modules"], 1, "Any .py file is automatically a module."),
    ("__name__ guard", "__name__ is '__main__' when run directly, module name when imported.", "# check.py\nif __name__ == '__main__':\n    print('Running directly')\nelse:\n    print('Being imported')", "Game: When is __name__ == '__main__'?\nA) When imported\nB) When run directly", "What is __name__ == '__main__'?", ["Always True", "True when file is the entry point", "An error", "A comment"], 1, "__name__ is '__main__' when the file is the entry point."),
    ("Packages", "A package is a folder with __init__.py. Groups related modules.", "# mypackage/\n#   __init__.py\n#   math_utils.py\n#   string_utils.py\n\nfrom mypackage.math_utils import add", "Game: What makes a folder a package?\nA) main.py\nB) __init__.py\nC) 10+ files", "What makes a folder a package?", ["main.py", "__init__.py", "Many files", "Being in root"], 1, "A folder is a package when it has __init__.py."),
    ("__all__ exports", "__all__ defines what 'from module import *' exports.", "# utils.py\n__all__ = ['add', 'subtract']\n\ndef add(a, b): return a + b\ndef subtract(a, b): return a - b\ndef _internal(): pass  # Not exported", "Game: What does __all__ control?\nA) All imports\nB) What import * exports\nC) The module name", "What does __all__ do?", ["Imports everything", "Controls what import * exports", "Deletes modules", "Creates packages"], 1, "__all__ defines the public API for import *."),
    ("Dynamic imports", "importlib.import_module() imports modules by name at runtime.", "import importlib\n\nmodule_name = 'math'\nmod = importlib.import_module(module_name)\nprint(mod.sqrt(16))  # 4.0", "Game: When is dynamic import useful?\nA) Always\nB) When module name is not known until runtime\nC) Never", "What is dynamic import?", ["Import at top of file", "Import by name at runtime", "Delete modules", "Create modules"], 1, "Dynamic import loads modules by name string at runtime."),
    ("Relative imports", "Use dots for relative imports within a package.", "# mypackage/sub/module.py\nfrom . import helper        # Same package\nfrom .. import utils       # Parent package\nfrom ..other import thing  # Sibling package", "Game: What does from . import x mean?\nA) Import from parent\nB) Import from same package\nC) Import from root", "What does . mean in imports?", ["Current package", "Parent package", "Root directory", "Error"], 1, ". = current package. .. = parent package."),
    ("Circular imports", "When two modules import each other. Can cause errors. Solution: import inside function.", "# a.py imports b\n# b.py imports a  # Circular!\n\n# Solution: import inside function\n# a.py\ndef func():\n    import b  # Import when needed\n    b.something()", "Game: How to fix circular imports?\nA) Delete one module\nB) Move import inside a function\nC) Use global", "How to fix circular imports?", ["Delete code", "Move import inside a function", "Use global", "Cannot fix"], 1, "Fix circular imports by importing inside functions."),
]

