ts_type_detailed = [
    ("TypeScript: JS + types", "TypeScript adds static types to JavaScript. Catches errors at compile time.", "// JS: no error until runtime\nfunction add(a, b) { return a + b; }\nadd('hi', 5); // Works but wrong!\n\n// TS: error at compile time\nfunction add(a: number, b: number) {\n    return a + b;\n}\nadd('hi', 5); // ERROR!", "Game: When does TS catch errors?\nA) Runtime\nB) Compile time\nC) Never", "When does TS catch type errors?", ["Runtime", "Compile time", "Never", "Only in prod"], 1, "TypeScript catches errors at compile time."),
    ("Primitive types", "string, number, boolean, null, undefined, symbol, bigint.", "let name: string = 'Alice';\nlet age: number = 25;\nlet active: boolean = true;\nlet nothing: null = null;\nlet undef: undefined = undefined;", "Game: What type is 3.14?\nA) string\nB) number\nC) float", "What type is 3.14 in TypeScript?", ["float", "number", "decimal", "double"], 1, "TypeScript has one number type: number."),
    ("Arrays", "Arrays hold multiple values of the same type.", "let nums: number[] = [1, 2, 3];\nlet names: Array<string> = ['a', 'b'];\n\n// TypeScript infers!\nlet cities = ['NYC', 'LA']; // string[]", "Game: What type is [1, 2, 3]?\nA) Array\nB) number[]\nC) list", "How do you type an array of numbers?", ["number[]", "Array<number>", "Both A and B", "[number]"], 1, "number[] or Array<number> for arrays of numbers."),
    ("Tuples", "Fixed-length arrays with specific types at each position.", "let pair: [string, number] = ['Alice', 25];\nlet triple: [number, number, number] = [1, 2, 3];\n\n// pair = [25, 'Alice']; // ERROR! Wrong order", "Game: What is the type of ['hello', 42]?\nA) Array\nB) [string, number]\nC) object", "What is a tuple?", ["Any array", "Fixed-length array with specific types", "A dictionary", "A function"], 1, "Tuples have fixed length with specific types at each position."),
    ("Object types", "Define the shape of objects with inline types.", "let user: { name: string; age: number } = {\n    name: 'Alice',\n    age: 25,\n};\n\n// user.email; // ERROR! Not in type", "Game: What properties must this object have?\ntype User = { name: string; age: number }", "How do you type an object?", ["With inline { } type", "With a class", "With any", "You cannot"], 1, "Object types use { prop: Type } syntax."),
    ("Interface", "Interfaces define object shapes. Reusable and extensible.", "interface User {\n    name: string;\n    age: number;\n    email?: string; // optional\n}\n\nconst alice: User = { name: 'Alice', age: 25 };", "Game: What does ? mean in email?: string?\nA) Required\nB) Optional\nC) Error", "What does ? mean in an interface?", ["Required", "Optional", "Delete", "Error"], 1, "? makes a property optional."),
    ("Type aliases", "type creates reusable type names. Can represent unions, intersections.", "type ID = string | number;\ntype Point = { x: number; y: number; };\n\ntype Result =\n    | { success: true; data: string }\n    | { success: false; error: string };", "Game: What does string | number mean?\nA) And\nB) Or\nC) Not", "What does | mean in types?", ["And", "Or (union)", "Not", "Delete"], 1, "| creates a union: value can be either type."),
    ("Function types", "Type function parameters and return values.", "function greet(name: string): string {\n    return `Hello, ${name}!`;\n}\n\nconst add = (a: number, b: number): number => a + b;", "Game: What type does (a: number) => number represent?\nA) A number\nB) A function taking number, returning number\nC) An array", "How do you type a function?", ["With interface", "With parameter and return types", "With any", "You cannot"], 1, "Type functions with (param: Type): ReturnType."),
    ("Generics", "Type parameters that get replaced with real types when called.", "function identity<T>(value: T): T {\n    return value;\n}\n\nidentity<string>('hello'); // T = string\nidentity<number>(42);      // T = number\nidentity('hi');             // T inferred as string", "Game: What type does identity(42) return?\nA) any\nB) number\nC) unknown", "What does <T> mean?", ["A comment", "A type parameter", "An HTML tag", "An error"], 1, "<T> is a type parameter. Gets replaced with actual type."),
    ("Type assertions", "Tell TypeScript you know the type better than it does.", "let value: unknown = 'hello';\nlet length = (value as string).length; // Assert!\n\n// Or angle bracket syntax\nlet length2 = (<string>value).length;", "Game: When use type assertions?\nA) Always\nB) When you know the type better than TS\nC) Never", "What is a type assertion?", ["A type error", "Telling TS you know the type", "Creating a type", "Deleting a type"], 1, "Type assertions tell TypeScript you know the type."),
]

gen_basics(5, "ts-types", ts_type_detailed)

ts_func_detailed = [
    ("Typed functions", "Type parameters and return values for safety.", "function add(a: number, b: number): number {\n    return a + b;\n}\n\nconst multiply = (a: number, b: number): number => a * b;", "Game: What type does add return?\nfunction add(a: number, b: number) { return a + b; }", "How to type a function?", ["function name(param: Type): ReturnType", "function name(param) -> Type", "def name(param: Type)", "fn name(param: Type)"], 1, "Use (param: Type): ReturnType for function types."),
    ("Optional parameters", "Use ? to make parameters optional.", "function greet(name: string, greeting?: string): string {\n    return `${greeting ?? 'Hello'}, ${name}!`;\n}\n\ngreet('Alice');          // Hello, Alice!\ngreet('Bob', 'Hi');      // Hi, Bob!", "Game: What does ? mean in a parameter?\nA) Required\nB) Optional\nC) Error", "How to make a parameter optional?", ["Use ?", "Use *", "Use default", "You cannot"], 1, "? makes a parameter optional: greeting?: string."),
    ("Default parameters", "Give parameters default values.", "function greet(name: string, greeting = 'Hello'): string {\n    return `${greeting}, ${name}!`;\n}\n\ngreet('Alice');      // Hello, Alice!\ngreet('Bob', 'Hi');  // Hi, Bob!", "Game: What does greet('Alice') return?\nfunction greet(name: string, msg = 'Hey') { ... }", "What is a default parameter?", ["Required", "Parameter with fallback value", "An error", "A type"], 1, "Default parameters have fallback values."),
    ("Rest parameters", "...args collects extra arguments into an array.", "function sum(...numbers: number[]): number {\n    return numbers.reduce((a, b) => a + b, 0);\n}\n\nsum(1, 2, 3);      // 6\nsum(1, 2, 3, 4);   // 10", "Game: What does sum(10, 20) return?\nfunction sum(...nums: number[]) { return nums.reduce((a,b) => a+b); }", "What does ...args do?", ["Creates a list", "Collects extra arguments into an array", "Deletes args", "Imports args"], 1, "...args collects extra arguments into an array."),
    ("Function overloads", "Multiple type signatures for one implementation.", "function format(value: string): string;\nfunction format(value: number): string;\nfunction format(value: string | number): string {\n    if (typeof value === 'string') return value;\n    return value.toFixed(2);\n}\n\nformat('hello'); // OK\nformat(3.14);    // OK", "Game: Why use overloads?\nA) For different implementations\nB) For precise types per call\nC) For speed", "What are function overloads?", ["Multiple implementations", "Multiple type signatures for one implementation", "Error handling", "Import syntax"], 1, "Overloads define multiple signatures for one implementation."),
    ("Higher-order functions", "Functions that take or return other functions.", "function apply(\n    fn: (x: number) => number,\n    value: number\n): number {\n    return fn(value);\n}\n\napply(x => x * 2, 5);  // 10", "Game: What is a higher-order function?\nA) A fast function\nB) A function that takes/returns functions\nC) A class method", "What is a higher-order function?", ["A fast function", "Takes or returns other functions", "A class", "An error"], 1, "Higher-order functions take or return functions."),
    ("Currying", "Transform f(a, b) into f(a)(b).", "function add(a: number): (b: number) => number {\n    return (b) => a + b;\n}\n\nconst add5 = add(5);\nadd5(3);  // 8\nadd5(10); // 15", "Game: What does add(2)(3) return?\nfunction add(a: number) { return (b: number) => a + b; }", "What is currying?", ["A cooking technique", "f(a, b) -> f(a)(b)", "A loop", "A type error"], 1, "Currying transforms multi-arg functions into single-arg chains."),
    ("Pipe function", "Chain functions left-to-right.", "const pipe = <T>(...fns: Array<(x: T) => T>) =>\n    (x: T) => fns.reduce((acc, fn) => fn(acc), x);\n\nconst process = pipe(\n    (x: number) => x + 1,\n    (x: number) => x * 2,\n);\nprocess(5); // 12", "Game: What does pipe(x => x+1, x => x*2)(3) return?", "What does pipe() do?", ["Creates plumbing", "Chains functions left-to-right", "Deletes functions", "Runs in parallel"], 1, "Pipe chains functions: output of one feeds input of next."),
]

gen_basics(5, "ts-functions", ts_func_detailed)

# TypeScript interfaces detailed
ts_iface_detailed = [
    ("Interface basics", "Interfaces define object shapes. Reusable, extensible.", "interface User {\n    name: string;\n    age: number;\n}\n\nconst user: User = { name: 'Alice', age: 25 };", "Game: What must a User have?\ninterface User { name: string; age: number; }", "What does an interface define?", ["A class", "The shape of an object", "A function", "A variable"], 1, "Interfaces define what properties an object must have."),
    ("Optional properties", "Use ? for properties that may or may not exist.", "interface Config {\n    host: string;\n    port?: number;    // optional\n    debug?: boolean;  // optional\n}\n\nconst c1: Config = { host: 'localhost' };\nconst c2: Config = { host: 'localhost', port: 3000 };", "Game: Is port required?\ninterface Config { host: string; port?: number; }", "What does ? do?", ["Makes required", "Makes optional", "Deletes", "Errors"], 1, "? makes the property optional."),
    ("Readonly properties", "readonly prevents modification after creation.", "interface Point {\n    readonly x: number;\n    readonly y: number;\n}\n\nconst p: Point = { x: 1, y: 2 };\n// p.x = 3; // ERROR! Readonly", "Game: Can you change a readonly property?\nA) Yes\nB) No", "What does readonly do?", ["Nothing", "Prevents modification after creation", "Deletes the property", "Makes it optional"], 1, "readonly prevents modification after object creation."),
    ("Extending interfaces", "Use extends to inherit from another interface.", "interface Animal {\n    name: string;\n}\n\ninterface Dog extends Animal {\n    breed: string;\n}\n\nconst rex: Dog = { name: 'Rex', breed: 'Lab' };", "Game: What properties does Dog have?\ninterface Dog extends Animal { breed: string; }", "What does extends do?", ["Deletes", "Inherits properties from parent", "Creates a class", "Imports"], 1, "extends inherits all properties from the parent interface."),
    ("Intersection types", "Combine types with &. Must have ALL properties.", "type Named = { name: string; };\ntype Aged = { age: number; };\n\ntype Person = Named & Aged;\n// Person must have BOTH name and age\nconst p: Person = { name: 'Alice', age: 25 };", "Game: What does { a } & { b } require?\nA) a or b\nB) Both a and b\nC) Neither", "What does & do?", ["Or", "And (intersection)", "Not", "Delete"], 1, "& creates intersection: must have ALL properties."),
    ("Mapped types", "Transform each property in a type.", "type Optional<T> = {\n    [K in keyof T]?: T[K];\n};\n\ntype User = { name: string; age: number; };\ntype PartialUser = Optional<User>;\n// { name?: string; age?: number; }", "Game: What does Partial<T> produce?\nA) All required\nB) All optional\nC) No properties", "What does a mapped type do?", ["Creates new type by transforming properties", "Maps coordinates", "Deletes properties", "Imports types"], 1, "Mapped types transform each property in a type."),
    ("Conditional types", "Types based on conditions, like ternary for types.", "type IsString<T> = T extends string ? 'yes' : 'no';\n\ntype A = IsString<string>;  // 'yes'\ntype B = IsString<number>;  // 'no'", "Game: What is IsString<boolean>?\ntype IsString<T> = T extends string ? 'yes' : 'no';", "What does a conditional type do?", ["Checks at runtime", "Creates types based on conditions", "Deletes types", "Imports modules"], 1, "Conditional types use extends + ternary for type-level logic."),
    ("Utility types", "Built-in type transformations: Partial, Required, Pick, Omit.", "type User = { name: string; age: number; email: string; };\n\ntype PartialUser = Partial<User>;     // all optional\ntype RequiredUser = Required<User>;   // all required\ntype NameOnly = Pick<User, 'name'>;   // { name: string }\ntype NoEmail = Omit<User, 'email'>;   // { name, age }", "Game: What does Pick<User, 'name'> produce?", "What does Partial<T> do?", ["All required", "All optional", "Deletes all", "Renames all"], 1, "Partial<T> makes every property optional."),
]

gen_basics(6, "ts-interfaces", ts_iface_detailed)

# TypeScript async detailed
ts_async_detailed = [
    ("Promises", "A Promise represents a future value. Pending -> fulfilled or rejected.", "const p = new Promise<string>((resolve, reject) => {\n    setTimeout(() => resolve('Done!'), 1000);\n});\n\np.then(result => console.log(result));", "Game: What states can a Promise be in?\nA) pending, fulfilled, rejected\nB) start, end\nC) open, closed", "What is a Promise?", ["A guarantee", "A future value", "A function", "A variable"], 1, "Promise = future value. Pending -> fulfilled or rejected."),
    ("async/await", "async/await makes Promise code look synchronous.", "async function fetchUser(): Promise<string> {\n    const res = await fetch('/api/user');\n    const data = await res.json();\n    return data.name;\n}", "Game: What does await do?\nA) Blocks thread\nB) Pauses until Promise resolves\nC) Creates a Promise", "What does await do?", ["Blocks everything", "Pauses until Promise resolves", "Creates a Promise", "Deletes a Promise"], 1, "await pauses until the Promise resolves."),
    ("Promise.all", "Wait for all promises to resolve. Runs concurrently.", "const results = await Promise.all([\n    fetch('/api/a'),\n    fetch('/api/b'),\n    fetch('/api/c'),\n]);\n// Total time = longest request", "Game: If each takes 1s, how long for Promise.all of 3?\nA) 3s\nB) 1s\nC) 0s", "What does Promise.all do?", ["Runs sequentially", "Runs concurrently, waits for all", "Takes fastest", "Cancels all"], 1, "Promise.all runs concurrently. Total = longest task."),
    ("Promise.allSettled", "Never rejects. Waits for all to settle (resolve or reject).", "const results = await Promise.allSettled([\n    fetch('/api/ok'),\n    fetch('/api/fail'),\n]);\nresults.forEach(r => {\n    if (r.status === 'fulfilled') console.log(r.value);\n    else console.log(r.reason);\n});", "Game: Does allSettled reject if one fails?\nA) Yes\nB) No", "What is the difference between all and allSettled?", ["Same", "allSettled never rejects", "allSettled is faster", "allSettled takes one"], 1, "allSettled waits for all, regardless of success/failure."),
    ("Promise.race", "Resolves/rejects with the FIRST promise to settle.", "const fastest = await Promise.race([\n    fetch('/api/slow'),   // 5s\n    fetch('/api/fast'),   // 1s\n]);\n// Resolves after 1s with fast result", "Game: What does Promise.race return?\nA) All results\nB) First result to settle\nC) Last result", "What does Promise.race do?", ["Waits for all", "Returns first to settle", "Cancels all", "Runs sequentially"], 1, "race() returns the first promise to settle."),
    ("AbortController", "Cancel fetch requests.", "const controller = new AbortController();\n\nfetch('/api/data', { signal: controller.signal })\n    .then(res => res.json())\n    .catch(err => {\n        if (err.name === 'AbortError') console.log('Cancelled!');\n    });\n\nsetTimeout(() => controller.abort(), 5000);", "Game: How to cancel a fetch?\nA) fetch.cancel()\nB) AbortController\nC) Cannot cancel", "How to cancel a fetch?", [".cancel()", "AbortController signal", "Close browser", "Wait"], 1, "AbortController provides a signal to cancel fetches."),
    ("Error handling", "Use try/catch with async/await for error handling.", "async function fetchData() {\n    try {\n        const res = await fetch('/api/data');\n        if (!res.ok) throw new Error(`HTTP ${res.status}`);\n        return await res.json();\n    } catch (error) {\n        console.error('Failed:', error);\n        return null;\n    }\n}", "Game: Where do you catch errors with async/await?\nA) In .then()\nB) In try/catch\nC) In .finally()", "How to handle async errors?", [".catch()", "try/catch", "if/else", "console.log"], 1, "Use try/catch with async/await for error handling."),
]

