# TypeScript modules detailed
ts_mod_detailed = [
    ("ES modules", "import/export are the standard way to share code.", "// math.ts\nexport function add(a: number, b: number) {\n    return a + b;\n}\nexport const PI = 3.14159;\n\n// main.ts\nimport { add, PI } from './math';", "Game: How to import add?\nA) require('./math').add\nB) import { add } from './math'\nC) include add", "How to export a function?", ["export function add(){}", "function add() export", "module.exports = add", "public function add"], 1, "Put 'export' before the declaration."),
    ("Default exports", "One default export per module. Import without braces.", "// Logger.ts\nexport default class Logger {\n    log(msg: string) { console.log(msg); }\n}\n\n// main.ts\nimport Logger from './Logger';", "Game: What is the difference?\nimport X from './X';\nimport { X } from './X';", "How to import default?", ["import { X } from '...'", "import X from '...'", "require('...')", "include X"], 1, "Default: import X from '...'. Named: import { X } from '...'."),
    ("Named exports", "Export multiple items by name. Import specific ones.", "// utils.ts\nexport const PI = 3.14;\nexport function add(a: number, b: number) { return a + b; }\n\n// main.ts\nimport { PI, add } from './utils';\nimport * as utils from './utils';", "Game: How to import everything?\nA) import * from './utils'\nB) import * as utils from './utils'\nC) import all from './utils'", "How to import all named exports?", ["import * from '...'", "import * as name from '...'", "import all from '...'", "Cannot import all"], 1, "import * as name from '...' imports all named exports."),
    ("Dynamic import", "import() loads modules on demand. Returns a Promise.", "async function loadChart() {\n    const { Chart } = await import('./Chart');\n    new Chart().render();\n}\n// Only loads when called!", "Game: When does dynamic import load?\nA) At startup\nB) When import() is called\nC) Never", "What is dynamic import?", ["Import at top", "Loading on demand with import()", "Deleting modules", "Importing from web"], 1, "import() loads modules on demand, returning a Promise."),
    ("Barrel files", "index.ts re-exports from multiple modules for cleaner imports.", "// utils/index.ts\nexport { add, subtract } from './math';\nexport { formatDate } from './dates';\n\n// main.ts\nimport { add, formatDate } from './utils';", "Game: What does a barrel file do?\nA) Stores data\nB) Re-exports for cleaner imports\nC) Deletes modules", "What is a barrel file?", ["Data store", "index.ts that re-exports", "Config file", "Test file"], 1, "Barrel files aggregate exports for cleaner imports."),
    ("Module resolution", "How TypeScript finds imported modules.", "// tsconfig.json paths\n{\n    \"compilerOptions\": {\n        \"paths\": {\n            \"@/*\": [\"./src/*\"]\n        }\n    }\n}\n\n// Now you can:\nimport { add } from '@/utils/math';", "Game: What does @/ mean?\nA) A URL\nB) A path alias\nC) An error", "What is module resolution?", ["How TS finds modules", "How TS compiles code", "How TS deletes code", "How TS runs"], 1, "Module resolution is how TypeScript finds imported modules."),
    ("Re-exporting", "Export items from other modules.", "// index.ts\nexport { User } from './models/User';\nexport { Post } from './models/Post';\nexport type { UserProps } from './types';\n\n// Re-export everything\nexport * from './utils';", "Game: What does export { X } from './Y' do?\nA) Imports X\nB) Imports and re-exports X\nC) Deletes X", "What is re-exporting?", ["Importing", "Exporting items from other modules", "Deleting modules", "Creating modules"], 1, "Re-exporting makes items available from a different module."),
]

