# TypeScript decorators detailed
ts_dec_detailed = [
    ("Decorators overview", "Decorators modify classes, methods, or properties at definition time.", "function Log(target: any, key: string) {\n    console.log(`${key} was defined`);\n}\n\nclass User {\n    @Log\n    name: string = 'Alice';\n}", "Game: When do decorators run?\nA) At instantiation\nB) At class definition\nC) Never", "When do decorators execute?", ["At instantiation", "At definition time", "At runtime", "Never"], 1, "Decorators execute at definition time, not instantiation."),
    ("Class decorators", "Receive the constructor. Can modify or replace it.", "function Sealed(constructor: Function) {\n    Object.seal(constructor);\n    Object.seal(constructor.prototype);\n}\n\n@Sealed\nclass User { name: string = 'Alice'; }", "Game: What does a class decorator receive?\nA) An instance\nB) The constructor\nC) Nothing", "What does a class decorator receive?", ["Instance", "Constructor function", "Class name", "Nothing"], 1, "Class decorators receive the constructor function."),
    ("Method decorators", "Can wrap or modify method behavior.", "function Log(target: any, key: string, desc: PropertyDescriptor) {\n    const original = desc.value;\n    desc.value = function(...args: any[]) {\n        console.log(`Calling ${key}`);\n        return original.apply(this, args);\n    };\n}\n\nclass Calculator {\n    @Log\n    add(a: number, b: number) { return a + b; }\n}", "Game: What can method decorators do?\nA) Only log\nB) Modify, wrap, or replace methods\nC) Delete methods", "What can method decorators do?", ["Only log", "Modify/wrap/replace methods", "Delete methods", "Nothing"], 1, "Method decorators can modify the method descriptor."),
    ("Property decorators", "Add metadata or validation to properties.", "function Required(target: any, key: string) {\n    Reflect.defineMetadata('required', true, target, key);\n}\n\nclass User {\n    @Required\n    name: string = '';\n}", "Game: What is a common use?\nA) Deleting properties\nB) Adding validation/metadata\nC) Making public", "What are property decorators for?", ["Deleting properties", "Adding validation or metadata", "Creating properties", "Importing"], 1, "Property decorators commonly add validation or metadata."),
    ("Decorator factories", "Functions that return decorators. Allow configuration.", "function MinLength(min: number) {\n    return function(target: any, key: string) {\n        // Validate min length\n    };\n}\n\nclass User {\n    @MinLength(3)\n    name: string = '';\n}", "Game: What is a decorator factory?\nA) A decorator\nB) A function that returns a decorator\nC) A class", "What is a decorator factory?", ["A decorator", "Function that returns a decorator", "A class", "An error"], 1, "Decorator factories are functions that return decorators."),
    ("Parameter decorators", "Decorate function parameters. Often used for DI.", "function Inject(token: string) {\n    return function(target: any, key: string, index: number) {\n        // Store injection metadata\n    };\n}\n\nclass UserService {\n    constructor(@Inject('DB') private db: Database) {}\n}", "Game: What do parameter decorators receive?\nA) The value\nB) Target, key, and parameter index\nC) Nothing", "What do parameter decorators receive?", ["The value", "Target, key, parameter index", "Nothing", "The type"], 1, "Parameter decorators receive target, key, and parameter index."),
    ("Reflect metadata", "Store and retrieve metadata on decorated targets.", "import 'reflect-metadata';\n\nfunction Type(type: Function) {\n    return Reflect.metadata('design:type', type);\n}\n\nclass User {\n    @Type(String)\n    name: string;\n}", "Game: What does Reflect.metadata do?\nA) Creates a class\nB) Stores/retrieves metadata\nC) Deletes code", "What is Reflect metadata?", ["A class", "Stores/retrieves metadata on targets", "A function", "An error"], 1, "Reflect metadata stores extra information on decorated targets."),
    ("Decorators in practice", "Real-world: logging, validation, dependency injection, authorization.", "@Controller('/users')\nclass UserController {\n    @Get('/:id')\n    @Authorize('admin')\n    @Cache(60)\n    getUser(@Param('id') id: string) {\n        return this.userService.findById(id);\n    }\n}", "Game: What do these decorators do?\n@Controller, @Get, @Authorize, @Cache", "What are real-world decorator uses?", ["Only logging", "Logging, validation, DI, auth, caching", "Nothing", "Only types"], 1, "Decorators are used for logging, validation, DI, auth, caching, and more."),
]

