patterns_detailed = [
    ("DI: concept", "Pass dependencies from outside instead of creating inside. Makes code testable.", "# Without DI\nclass Service:\n    def __init__(self):\n        self.db = MySQL()  # Hardcoded!\n\n# With DI\nclass Service:\n    def __init__(self, db):\n        self.db = db  # Passed in!", "Game: Which is easier to test?\nA) Hardcoded dependency\nB) Passed-in dependency", "What is DI?", ["Creating inside", "Passing from outside", "A database", "A loop"], 1, "DI passes dependencies from outside. Enables testing and flexibility."),
    ("DI: FastAPI pattern", "FastAPI uses Depends() for dependency injection.", "def get_db():\n    db = Session()\n    try:\n        yield db\n    finally:\n        db.close()\n\n@app.get('/users')\ndef list_users(db = Depends(get_db)):\n    return db.query(User).all()", "Game: What does Depends() do?\nA) Creates a dependency\nB) Resolves and injects\nC) Deletes a dependency", "How does FastAPI DI work?", ["Manual call", "Auto-resolve from type hints", "Config files", "Env vars"], 1, "FastAPI inspects types and auto-injects dependencies."),
    ("Middleware: concept", "Middleware intercepts requests. Can modify, log, or reject.", "# Middleware chain\nrequest -> auth -> logging -> handler -> response\n\n# Each middleware can:\n# 1. Modify the request\n# 2. Call the next middleware\n# 3. Modify the response\n# 4. Short-circuit (reject early)", "Game: Where does middleware sit?\nA) In the database\nB) Between request and handler\nC) After response", "What does middleware do?", ["In DB", "Intercepts between request and handler", "After response", "Only on errors"], 1, "Middleware intercepts requests before they reach the handler."),
    ("Builder: concept", "Build complex objects step by step. Method chaining.", "class QueryBuilder:\n    def __init__(self):\n        self._table = ''\n        self._conditions = []\n    def table(self, name):\n        self._table = name\n        return self\n    def where(self, cond):\n        self._conditions.append(cond)\n        return self\n    def build(self):\n        return f'SELECT * FROM {self._table} WHERE {\" AND \".join(self._conditions)}'\n\nquery = QueryBuilder().table('users').where('age > 18').build()", "Game: What does .table('x').where('y').build() produce?", "Why use Builder?", ["For simple objects", "For complex objects with chaining", "To delete objects", "To import"], 1, "Builder constructs complex objects step by step with chaining."),
    ("Strategy: concept", "Swap algorithms at runtime behind a common interface.", "class Sorter:\n    def __init__(self, strategy):\n        self.strategy = strategy\n    def sort(self, data):\n        return self.strategy(data)\n\n# Swap at runtime!\nsorter = Sorter(sorted)\nprint(sorter.sort([3,1,2]))\nsorter.strategy = lambda d: sorted(d, reverse=True)", "Game: How to swap algorithm?\nA) Rewrite class\nB) Change strategy object\nC) Cannot swap", "What does Strategy do?", ["Deletes algorithms", "Swaps algorithms at runtime", "Runs all", "Creates new"], 1, "Strategy makes algorithms interchangeable at runtime."),
    ("Observer: concept", "One object changes, many subscribers notified.", "class EventEmitter:\n    def __init__(self):\n        self._listeners = {}\n    def on(self, event, fn):\n        self._listeners.setdefault(event, []).append(fn)\n    def emit(self, event, *args):\n        for fn in self._listeners.get(event, []):\n            fn(*args)\n\nee = EventEmitter()\nee.on('click', lambda: print('Clicked!'))\nee.emit('click')  # Clicked!", "Game: What happens on emit('click')?\nA) Nothing\nB) All click listeners fire\nC) Program exits", "What does Observer do?", ["Deletes events", "Notifies subscribers on change", "Creates loops", "Imports"], 1, "Observer enables one-to-many notification."),
    ("Factory: concept", "Create objects without specifying the exact class.", "class AnimalFactory:\n    @staticmethod\n    def create(type):\n        if type == 'dog': return Dog()\n        if type == 'cat': return Cat()\n        raise ValueError(f'Unknown: {type}')\n\nanimal = AnimalFactory.create('dog')\nanimal.speak()  # Woof!", "Game: What does Factory decide?\nA) How to delete\nB) Which class to instantiate\nC) How to sort", "What does Factory do?", ["Deletes objects", "Creates objects without specifying class", "Sorts objects", "Imports"], 1, "Factory encapsulates object creation."),
    ("Repository: concept", "Abstract data access. Business logic doesn't know about the DB.", "class UserRepository:\n    def __init__(self, db): self.db = db\n    def find_by_id(self, id):\n        return self.db.query('SELECT * FROM users WHERE id=?', [id])\n    def save(self, user):\n        self.db.execute('INSERT INTO users ...', user)", "Game: What does Repository hide?\nA) UI\nB) Data access details\nC) Network", "What does Repository abstract?", ["UI", "Data access from business logic", "Network", "Files"], 1, "Repository hides data access details from business logic."),
    ("Pipeline: concept", "Chain processing stages. Output of one feeds the next.", "class Pipeline:\n    def __init__(self): self.stages = []\n    def add(self, fn):\n        self.stages.append(fn)\n        return self\n    def execute(self, data):\n        result = data\n        for stage in self.stages:\n            result = stage(result)\n        return result\n\npipe = Pipeline()\npipe.add(lambda x: x.strip())\npipe.add(lambda x: x.lower())\npipe.execute('  HELLO  ')  # 'hello'", "Game: What does pipe(x => x+1, x => x*2)(5) produce?", "What does Pipeline do?", ["Parallel", "Chains stages sequentially", "Deletes data", "Imports"], 1, "Pipeline chains processing stages: input -> stage1 -> stage2 -> output."),
]

