    ("FastAPI: query params", "After ? in the URL. Have defaults.", "@app.get('/search')\ndef search(q: str, limit: int = 10):\n    return {'q': q, 'limit': limit}", "Game: What is limit for /search?q=test?", "How to set default?", ["@default", "Default value in signature", "Config file", "Cannot set"], 1, "Default values in function signature."),
