# ============================================================
# Generate output
# ============================================================

def main():
    weeks = {}
    for kp_item in ALL_KP:
        week = kp_item["week"]
        module = kp_item["module"]
        if week not in weeks:
            weeks[week] = {}
        if module not in weeks[week]:
            weeks[week][module] = []
        weeks[week][module].append(kp_item)

    output = {
        "total_points": len(ALL_KP),
        "weeks": len(weeks),
        "points": ALL_KP,
        "by_week": {str(w): {m: len(v) for m, v in mods.items()} for w, mods in sorted(weeks.items())},
    }

    out_path = Path(__file__).parent / "data" / "knowledge_points.json"
    out_path.write_text(json.dumps(output, indent=2, ensure_ascii=False), encoding="utf-8")
    print(f"Generated {len(ALL_KP)} knowledge points -> {out_path}")

    for week, modules in sorted(weeks.items()):
        total = sum(len(v) for v in modules.values())
        print(f"  Week {week}: {total} points across {len(modules)} modules")

if __name__ == "__main__":
    main()
